31	pub const TOML = struct {
32	    lexer: Lexer,
33	    log: *logger.Log,
34	    allocator: std.mem.Allocator,
35	    stack_check: bun.StackCheck,
36	
37	    pub fn init(allocator: std.mem.Allocator, source_: logger.Source, log: *logger.Log, redact_logs: bool) !TOML {
38	        return TOML{
39	            .lexer = try Lexer.init(log, source_, allocator, redact_logs),
40	            .allocator = allocator,
41	            .log = log,
42	            .stack_check = bun.StackCheck.init(),
43	        };
44	    }
45	
46	    pub inline fn source(p: *const TOML) *const logger.Source {
47	        return &p.lexer.source;
48	    }
49	
50	    pub fn e(_: *TOML, t: anytype, loc: logger.Loc) Expr {
51	        const Type = @TypeOf(t);
52	        if (@typeInfo(Type) == .pointer) {
53	            return Expr.init(std.meta.Child(Type), t.*, loc);
54	        } else {
55	            return Expr.init(Type, t, loc);
56	        }
57	    }
58	
59	    const Rope = js_ast.E.Object.Rope;
60	
61	    pub fn parseKeySegment(p: *TOML) anyerror!?Expr {
62	        const loc = p.lexer.loc();
63	
64	        switch (p.lexer.token) {
65	            .t_string_literal => {
66	                const str = p.lexer.toString(loc);
67	                try p.lexer.next();
68	                return str;
69	            },
70	            .t_identifier => {
71	                const str = E.String{ .data = p.lexer.identifier };
72	                try p.lexer.next();
73	                return p.e(str, loc);
74	            },
75	            .t_false => {
76	                try p.lexer.next();
77	                return p.e(
78	                    E.String{
79	                        .data = "false",
80	                    },
81	                    loc,
82	                );
83	            },
84	            .t_true => {
85	                try p.lexer.next();
86	                return p.e(
87	                    E.String{
88	                        .data = "true",
89	                    },
90	                    loc,
91	                );
92	            },
93	            // what we see as a number here could actually be a string
94	            .t_numeric_literal => {
95	                const literal = p.lexer.raw();
96	                try p.lexer.next();
97	                return p.e(E.String{ .data = literal }, loc);
98	            },
99	
100	            else => return null,
101	        }
102	    }
103	
104	    pub fn parseKey(p: *TOML, allocator: std.mem.Allocator) anyerror!*Rope {
105	        var rope = try allocator.create(Rope);
106	        const head = rope;
107	        rope.* = .{
108	            .head = (try p.parseKeySegment()) orelse {
109	                try p.lexer.expectedString("key");
110	                return error.SyntaxError;
111	            },
112	            .next = null,
113	        };
114	        while (p.lexer.token == .t_dot) {
115	            try p.lexer.next();
116	
117	            rope = try rope.append((try p.parseKeySegment()) orelse break, allocator);
118	        }
119	
120	        return head;
121	    }
122	
123	    pub fn parse(source_: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator, redact_logs: bool) !Expr {
124	        switch (source_.contents.len) {
125	            // This is to be consisntent with how disabled JS files are handled
126	            0 => {
127	                return Expr{ .loc = logger.Loc{ .start = 0 }, .data = Expr.init(E.Object, E.Object{}, logger.Loc.Empty).data };
128	            },
129	            else => {},
130	        }
131	
132	        var parser = try TOML.init(allocator, source_.*, log, redact_logs);
133	
134	        return try parser.runParser();
135	    }
136	
137	    fn runParser(p: *TOML) anyerror!Expr {
138	        var root = p.e(E.Object{}, p.lexer.loc());
139	        var head = root.data.e_object;
140	
141	        var stack = std.heap.stackFallback(@sizeOf(Rope) * 6, p.allocator);
142	        const key_allocator = stack.get();
143	
144	        while (true) {
145	            const loc = p.lexer.loc();
146	            switch (p.lexer.token) {
147	                .t_end_of_file => {
148	                    return root;
149	                },
150	                // child table
151	                .t_open_bracket => {
152	                    try p.lexer.next();
153	                    const key = try p.parseKey(key_allocator);
154	
155	                    try p.lexer.expect(.t_close_bracket);
156	                    if (!p.lexer.has_newline_before) {
157	                        try p.lexer.expectedString("line break");
158	                    }
159	
160	                    const parent_object = root.data.e_object.getOrPutObject(key, p.allocator) catch |err| {
161	                        switch (err) {
162	                            error.Clobber => {
163	                                try p.lexer.addDefaultError("Table already defined");
164	                                return error.SyntaxError;
165	                            },
166	                            else => return err,
167	                        }
168	                    };
169	                    head = parent_object.data.e_object;
170	                    stack.fixed_buffer_allocator.reset();
171	                },
172	                // child table array
173	                .t_open_bracket_double => {
174	                    try p.lexer.next();
175	
176	                    const key = try p.parseKey(key_allocator);
177	
178	                    try p.lexer.expect(.t_close_bracket_double);
179	                    if (!p.lexer.has_newline_before) {
180	                        try p.lexer.expectedString("line break");
181	                    }
182	
183	                    var array = root.data.e_object.getOrPutArray(key, p.allocator) catch |err| {
184	                        switch (err) {
185	                            error.Clobber => {
186	                                try p.lexer.addDefaultError("Cannot overwrite table array");
187	                                return error.SyntaxError;
188	                            },
189	                            else => return err,
190	                        }
191	                    };
192	                    const new_head = p.e(E.Object{}, loc);
193	                    try array.data.e_array.push(p.allocator, new_head);
194	                    head = new_head.data.e_object;
195	                    stack.fixed_buffer_allocator.reset();
196	                },
197	                else => {
198	                    try p.parseAssignment(head, key_allocator);
199	                    stack.fixed_buffer_allocator.reset();
200	                },
201	            }
202	        }
203	    }
204	
205	    pub fn parseAssignment(p: *TOML, obj: *E.Object, allocator: std.mem.Allocator) anyerror!void {
206	        p.lexer.allow_double_bracket = false;
207	        const rope = try p.parseKey(allocator);
208	        const rope_end = p.lexer.start;
209	
210	        const is_array = p.lexer.token == .t_empty_array;
211	        if (is_array) {
212	            try p.lexer.next();
213	        }
214	
215	        try p.lexer.expectAssignment();
216	        if (!is_array) {
217	            obj.setRope(rope, p.allocator, try p.parseValue()) catch |err| {
218	                switch (err) {
219	                    error.Clobber => {
220	                        const loc = rope.head.loc;
221	                        assert(loc.start > 0);
222	                        const start: u32 = @intCast(loc.start);
223	                        const key_name = std.mem.trimRight(u8, p.source().contents[start..rope_end], &std.ascii.whitespace);
224	                        p.lexer.addError(start, "Cannot redefine key '{s}'", .{key_name});
225	                        return error.SyntaxError;
226	                    },
227	                    else => return err,
228	                }
229	            };
230	        }
231	        p.lexer.allow_double_bracket = true;
232	    }
233	
234	    pub fn parseValue(p: *TOML) anyerror!Expr {
235	        if (!p.stack_check.isSafeToRecurse()) {
236	            try bun.throwStackOverflow();
237	        }
238	
239	        const loc = p.lexer.loc();
240	
241	        p.lexer.allow_double_bracket = true;
242	
243	        switch (p.lexer.token) {
244	            .t_false => {
245	                try p.lexer.next();
246	
247	                return p.e(E.Boolean{
248	                    .value = false,
249	                }, loc);
250	            },
251	            .t_true => {
252	                try p.lexer.next();
253	                return p.e(E.Boolean{
254	                    .value = true,
255	                }, loc);
256	            },
257	            .t_string_literal => {
258	                const result = p.lexer.toString(loc);
259	                try p.lexer.next();
260	                return result;
261	            },
262	            .t_identifier => {
263	                const str: E.String = E.String{ .data = p.lexer.identifier };
264	
265	                try p.lexer.next();
266	                return p.e(str, loc);
267	            },
268	            .t_numeric_literal => {
269	                const value = p.lexer.number;
270	                try p.lexer.next();
271	                return p.e(E.Number{ .value = value }, loc);
272	            },
273	            .t_minus => {
274	                try p.lexer.next();
275	                const value = p.lexer.number;
276	
277	                try p.lexer.expect(.t_numeric_literal);
278	                return p.e(E.Number{ .value = -value }, loc);
279	            },
280	            .t_plus => {
281	                try p.lexer.next();
282	                const value = p.lexer.number;
283	
284	                try p.lexer.expect(.t_numeric_literal);
285	                return p.e(E.Number{ .value = value }, loc);
286	            },
287	            .t_open_brace => {
288	                try p.lexer.next();
289	                var is_single_line = !p.lexer.has_newline_before;
290	                var stack = std.heap.stackFallback(@sizeOf(Rope) * 6, p.allocator);
291	                const key_allocator = stack.get();
292	                const expr = p.e(E.Object{}, loc);
293	                const obj = expr.data.e_object;
294	
295	                while (p.lexer.token != .t_close_brace) {
296	                    if (obj.properties.len > 0) {
297	                        if (p.lexer.has_newline_before) {
298	                            is_single_line = false;
299	                        }
300	                        if (!try p.parseMaybeTrailingComma(.t_close_brace)) {
301	                            break;
302	                        }
303	                        if (p.lexer.has_newline_before) {
304	                            is_single_line = false;
305	                        }
306	                    }
307	                    try p.parseAssignment(obj, key_allocator);
308	                    p.lexer.allow_double_bracket = false;
309	                    stack.fixed_buffer_allocator.reset();
310	                }
311	
312	                if (p.lexer.has_newline_before) {
313	                    is_single_line = false;
314	                }
315	                p.lexer.allow_double_bracket = true;
316	                try p.lexer.expect(.t_close_brace);
317	                return expr;
318	            },
319	            .t_empty_array => {
320	                try p.lexer.next();
321	                p.lexer.allow_double_bracket = true;
322	                return p.e(E.Array{}, loc);
323	            },
324	            .t_open_bracket => {
325	                try p.lexer.next();
326	                var is_single_line = !p.lexer.has_newline_before;
327	                const array_ = p.e(E.Array{}, loc);
328	                var array = array_.data.e_array;
329	                const allocator = p.allocator;
330	                p.lexer.allow_double_bracket = false;
331	
332	                while (p.lexer.token != .t_close_bracket) {
333	                    if (array.items.len > 0) {
334	                        if (p.lexer.has_newline_before) {
335	                            is_single_line = false;
336	                        }
337	
338	                        if (!try p.parseMaybeTrailingComma(.t_close_bracket)) {
339	                            break;
340	                        }
341	
342	                        if (p.lexer.has_newline_before) {
343	                            is_single_line = false;
344	                        }
345	                    }
346	
347	                    array.push(allocator, try p.parseValue()) catch unreachable;
348	                }
349	
350	                if (p.lexer.has_newline_before) {
351	                    is_single_line = false;
352	                }
353	                p.lexer.allow_double_bracket = true;
354	                try p.lexer.expect(.t_close_bracket);
355	                return array_;
356	            },
357	            else => {
358	                try p.lexer.unexpected();
359	                return error.SyntaxError;
360	            },
361	        }
362	    }
363	
364	    pub fn parseMaybeTrailingComma(p: *TOML, closer: T) !bool {
365	        try p.lexer.expect(.t_comma);
366	
367	        if (p.lexer.token == closer) {
368	            return false;
369	        }
370	
371	        return true;
372	    }
373	};
