        var key_str = bun.String.fromUTF8(key_raw);
        defer key_str.deref();
        try current_section.putMayBeIndex(globalThis, &key_str, value);
    }

    return root;
}

fn parseValue(globalThis: *jsc.JSGlobalObject, raw: []const u8) jsc.JSValue {
    if (raw.len == 0) {
        return bun.String.empty.toJSConst(globalThis);
    }

    // Strip matching quotes
    const val = if (raw.len >= 2 and
        ((raw[0] == '"' and raw[raw.len - 1] == '"') or
        (raw[0] == '\'' and raw[raw.len - 1] == '\'')))
        raw[1 .. raw.len - 1]
    else
        raw;

    // Boolean/null coercion
    if (bun.strings.eqlComptime(val, "true")) return .jsBoolean(true);
    if (bun.strings.eqlComptime(val, "false")) return .jsBoolean(false);
    if (bun.strings.eqlComptime(val, "null")) return .null;

    var str = bun.String.fromUTF8(val);
    defer str.deref();
    return str.toJS(globalThis);
}

fn trimLine(raw: []const u8) []const u8 {
    var line = raw;
    // Strip trailing \r for CRLF
    if (line.len > 0 and line[line.len - 1] == '\r') {
        line = line[0 .. line.len - 1];
    }
    // Trim leading/trailing whitespace
    return std.mem.trim(u8, line, " \t");
}

pub fn stringify(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const arguments = callframe.arguments_old(1).slice();
    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    const value = arguments[0];
    if (!value.isObject()) {
        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    // First pass: emit root-level primitive key=value pairs
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try value.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            // Skip objects (sections) in first pass, skip undefined/functions/symbols
            if (prop_val.isObject() or prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) continue;

            appendKeyName(&builder, prop_name);
            builder.append(.latin1, " = ");
            try appendValue(&builder, globalThis, prop_val);
            builder.append(.lchar, '\n');
        }
    }

    // Second pass: emit sections (object values)
    {
        var first_section = true;
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            globalThis,
            try value.toObject(globalThis),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            // Only handle objects in second pass
            if (!prop_val.isObject() or prop_val.isFunction()) continue;

            if (!first_section or builder.count > 0) {
                builder.append(.lchar, '\n');
            }
            first_section = false;

            builder.append(.lchar, '[');
            appendKeyName(&builder, prop_name);
            builder.append(.latin1, "]\n");

            // Iterate section properties
            var section_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                globalThis,
                try prop_val.toObject(globalThis),
            );
            defer section_iter.deinit();

            while (try section_iter.next()) |section_prop_name| {
                const section_prop_val = section_iter.value;
                if (section_prop_val.isUndefined() or section_prop_val.isSymbol() or section_prop_val.isFunction()) continue;

                appendKeyName(&builder, section_prop_name);
                builder.append(.latin1, " = ");
                try appendValue(&builder, globalThis, section_prop_val);
                builder.append(.lchar, '\n');
            }
        }
    }

    return builder.toString(globalThis);
}

fn appendKeyName(builder: *wtf.StringBuilder, name: bun.String) void {
    builder.append(.string, name);
}

fn appendValue(builder: *wtf.StringBuilder, globalThis: *jsc.JSGlobalObject, val: jsc.JSValue) bun.JSError!void {
    if (val.isNull()) {
        builder.append(.latin1, "null");
        return;
    }

    if (val.isBoolean()) {
        builder.append(.latin1, if (val.asBoolean()) "true" else "false");
        return;
    }

    if (val.isNumber()) {
        if (val.isInt32()) {
            builder.append(.int, val.asInt32());
        } else {
            builder.append(.double, val.asNumber());
        }
        return;
    }

    if (val.isString()) {
        const str = try val.toBunString(globalThis);
        defer str.deref();
        builder.append(.string, str);
        return;
    }

    // For anything else (arrays, nested objects inside sections, etc.), use toString
    const str = try val.toBunString(globalThis);
    defer str.deref();
    builder.append(.string, str);
}

