import { describe, expect, test } from "bun:test";

describe("Bun.INI", () => {
  test("exists on Bun global", () => {
    expect(Bun.INI).toBeDefined();
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  describe("parse", () => {
    test("basic key=value pairs", () => {
      const result = Bun.INI.parse("key = value\nname = test");
      expect(result).toEqual({ key: "value", name: "test" });
    });

    test("key=value without spaces around =", () => {
      const result = Bun.INI.parse("key=value");
      expect(result).toEqual({ key: "value" });
    });

    test("sections as nested objects", () => {
      const result = Bun.INI.parse(`
[section]
key = value
name = test
`);
      expect(result).toEqual({ section: { key: "value", name: "test" } });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse(`
[first]
a = 1

[second]
b = 2
`);
      expect(result).toEqual({
        first: { a: "1" },
        second: { b: "2" },
      });
    });

    test("root-level and sectioned keys", () => {
      const result = Bun.INI.parse(`
root = hello

[section]
nested = world
`);
      expect(result).toEqual({
        root: "hello",
        section: { nested: "world" },
      });
    });

    test("semicolon comments are ignored", () => {
      const result = Bun.INI.parse(`
; this is a comment
key = value
; another comment
`);
      expect(result).toEqual({ key: "value" });
    });

    test("hash comments are ignored", () => {
      const result = Bun.INI.parse(`
# this is a comment
key = value
# another comment
`);
      expect(result).toEqual({ key: "value" });
    });

    test("empty lines are ignored", () => {
      const result = Bun.INI.parse(`

key = value

name = test

`);
      expect(result).toEqual({ key: "value", name: "test" });
    });

    test("boolean coercion: true", () => {
      const result = Bun.INI.parse("enabled = true");
      expect(result).toEqual({ enabled: true });
    });

    test("boolean coercion: false", () => {
      const result = Bun.INI.parse("enabled = false");
      expect(result).toEqual({ enabled: false });
    });

    test("null coercion", () => {
      const result = Bun.INI.parse("value = null");
      expect(result).toEqual({ value: null });
    });

    test("key without = becomes true", () => {
      const result = Bun.INI.parse("enabled");
      expect(result).toEqual({ enabled: true });
    });

    test("key with = but no value becomes empty string", () => {
      const result = Bun.INI.parse("key =");
      expect(result).toEqual({ key: "" });
    });

    test("double-quoted values have quotes stripped", () => {
      const result = Bun.INI.parse('key = "hello world"');
      expect(result).toEqual({ key: "hello world" });
    });

    test("single-quoted values have quotes stripped", () => {
      const result = Bun.INI.parse("key = 'hello world'");
      expect(result).toEqual({ key: "hello world" });
    });

    test("whitespace around keys and values is trimmed", () => {
      const result = Bun.INI.parse("  key  =  value  ");
      expect(result).toEqual({ key: "value" });
    });

    test("CRLF line endings", () => {
      const result = Bun.INI.parse("[section]\r\nkey = value\r\n");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("section with whitespace in header", () => {
      const result = Bun.INI.parse("[ section ]\nkey = value");
      expect(result).toEqual({ section: { key: "value" } });
    });

    test("duplicate section merges keys", () => {
      const result = Bun.INI.parse(`
[section]
a = 1

[section]
b = 2
`);
      expect(result).toEqual({ section: { a: "1", b: "2" } });
    });

    test("throws on no arguments", () => {
      expect(() => (Bun.INI.parse as any)()).toThrow();
    });

    test("throws on null argument", () => {
      expect(() => (Bun.INI.parse as any)(null)).toThrow();
    });

    test("throws on undefined argument", () => {
      expect(() => (Bun.INI.parse as any)(undefined)).toThrow();
    });

    test("empty string returns empty object", () => {
      const result = Bun.INI.parse("");
      expect(result).toEqual({});
    });

    test("only comments returns empty object", () => {
      const result = Bun.INI.parse("; comment\n# another comment");
      expect(result).toEqual({});
    });

    test("complex INI file", () => {
      const result = Bun.INI.parse(`
; Database configuration
[database]
host = localhost
port = 5432
name = mydb
enabled = true

# Server settings
[server]
host = 0.0.0.0
port = 8080
debug = false

[logging]
level = info
file = null
`);
      expect(result).toEqual({
        database: {
          host: "localhost",
          port: "5432",
          name: "mydb",
          enabled: true,
        },
        server: {
          host: "0.0.0.0",
          port: "8080",
          debug: false,
        },
        logging: {
          level: "info",
          file: null,
        },
      });
    });
  });

  describe("stringify", () => {
    test("basic object with primitive values", () => {
      const result = Bun.INI.stringify({ key: "value", name: "test" });
      expect(result).toBe("key = value\nname = test\n");
    });

    test("object with sections", () => {
      const result = Bun.INI.stringify({
        section: { key: "value" },
      });
      expect(result).toBe("[section]\nkey = value\n");
    });

    test("mixed root and sections", () => {
      const result = Bun.INI.stringify({
        root: "hello",
        section: { nested: "world" },
      });
      expect(result).toBe("root = hello\n\n[section]\nnested = world\n");
    });

    test("boolean values", () => {
      const result = Bun.INI.stringify({ enabled: true, disabled: false });
      expect(result).toBe("enabled = true\ndisabled = false\n");
    });

    test("null values", () => {
      const result = Bun.INI.stringify({ key: null });
      expect(result).toBe("key = null\n");
    });

    test("numeric values", () => {
      const result = Bun.INI.stringify({ port: 8080, ratio: 3.14 });
      expect(result).toBe("port = 8080\nratio = 3.14\n");
    });

    test("multiple sections", () => {
      const result = Bun.INI.stringify({
        first: { a: "1" },
        second: { b: "2" },
      });
      expect(result).toBe("[first]\na = 1\n\n[second]\nb = 2\n");
    });

    test("throws on no arguments", () => {
      expect(() => (Bun.INI.stringify as any)()).toThrow();
    });

    test("throws on non-object", () => {
      expect(() => (Bun.INI.stringify as any)("string")).toThrow();
    });

    test("empty object returns empty string", () => {
      const result = Bun.INI.stringify({});
      expect(result).toBe("");
    });
  });

  describe("round-trip", () => {
    test("parse then stringify preserves structure", () => {
      const input = `root = hello

[section]
key = value
enabled = true
`;
      const parsed = Bun.INI.parse(input);
      const stringified = Bun.INI.stringify(parsed);
      const reparsed = Bun.INI.parse(stringified);
      expect(reparsed).toEqual(parsed);
    });

    test("stringify then parse preserves structure", () => {
      const obj = {
        name: "test",
        database: { host: "localhost", port: "5432" },
        server: { debug: "false" },
      };
      const stringified = Bun.INI.stringify(obj);
      const parsed = Bun.INI.parse(stringified);
      expect(parsed).toEqual(obj);
    });
  });
});

