1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
7	    );
8	    object.put(
9	        globalThis,
10	        ZigString.static("stringify"),
11	        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
12	    );
13	    return object;
14	}
15	
16	pub fn parse(
17	    globalThis: *jsc.JSGlobalObject,
18	    callframe: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const arguments = callframe.arguments_old(1).slice();
21	    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
22	        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
23	    }
24	
25	    var input_slice = try arguments[0].toSlice(globalThis, bun.default_allocator);
26	    defer input_slice.deinit();
27	    const input = input_slice.slice();
28	
29	    const root = JSValue.createEmptyObject(globalThis, 0);
30	    var current_section = root;
31	
32	    var iter = std.mem.splitScalar(u8, input, '\n');
33	    while (iter.next()) |raw_line| {
34	        const line = trimLine(raw_line);
35	        if (line.len == 0) continue;
36	
37	        // Comments
38	        if (line[0] == ';' or line[0] == '#') continue;
39	
40	        // Section header: [section]
41	        if (line[0] == '[') {
42	            const close = std.mem.indexOfScalar(u8, line, ']') orelse continue;
43	            // Ensure rest after ] is whitespace only
44	            const after_bracket = std.mem.trimLeft(u8, line[close + 1 ..], " \t");
45	            if (after_bracket.len > 0) {
46	                // Not a valid section header — treat as a regular key line below
47	            } else {
48	                const section_name = std.mem.trim(u8, line[1..close], " \t");
49	                if (section_name.len == 0) continue;
50	
51	                // Check if section already exists
52	                var name_str = bun.String.fromUTF8(section_name);
53	                defer name_str.deref();
54	
55	                const existing = root.getWithString(globalThis, &name_str);
56	                if (existing != .zero and existing != .js_undefined) {
57	                    current_section = existing;
58	                } else {
59	                    const section_obj = JSValue.createEmptyObject(globalThis, 0);
60	                    try root.putMayBeIndex(globalThis, &name_str, section_obj);
61	                    current_section = section_obj;
62	                }
63	                continue;
64	            }
65	        }
66	
67	        // Key=value pair
68	        const eq_idx = std.mem.indexOfScalar(u8, line, '=');
69	        const key_raw = if (eq_idx) |idx| std.mem.trim(u8, line[0..idx], " \t") else std.mem.trim(u8, line, " \t");
70	
71	        if (key_raw.len == 0) continue;
72	
73	        const value: jsc.JSValue = if (eq_idx) |idx| blk: {
74	            const val_raw = if (idx + 1 < line.len)
75	                std.mem.trim(u8, line[idx + 1 ..], " \t")
76	            else
77	                "";
78	            break :blk parseValue(globalThis, val_raw);
79	        } else .jsBoolean(true); // key without = means true
80	
81	        var key_str = bun.String.fromUTF8(key_raw);
82	        defer key_str.deref();
83	        try current_section.putMayBeIndex(globalThis, &key_str, value);
84	    }
85	
86	    return root;
87	}
88	
89	fn parseValue(globalThis: *jsc.JSGlobalObject, raw: []const u8) jsc.JSValue {
90	    if (raw.len == 0) {
91	        return bun.String.empty.toJSConst(globalThis);
92	    }
93	
94	    // Strip matching quotes
95	    const val = if (raw.len >= 2 and
96	        ((raw[0] == '"' and raw[raw.len - 1] == '"') or
97	        (raw[0] == '\'' and raw[raw.len - 1] == '\'')))
98	        raw[1 .. raw.len - 1]
99	    else
100	        raw;
101	
102	    // Boolean/null coercion
103	    if (bun.strings.eqlComptime(val, "true")) return .jsBoolean(true);
104	    if (bun.strings.eqlComptime(val, "false")) return .jsBoolean(false);
105	    if (bun.strings.eqlComptime(val, "null")) return .null;
106	
107	    var str = bun.String.fromUTF8(val);
108	    defer str.deref();
109	    return str.toJS(globalThis);
110	}
111	
112	fn trimLine(raw: []const u8) []const u8 {
113	    var line = raw;
114	    // Strip trailing \r for CRLF
115	    if (line.len > 0 and line[line.len - 1] == '\r') {
116	        line = line[0 .. line.len - 1];
117	    }
118	    // Trim leading/trailing whitespace
119	    return std.mem.trim(u8, line, " \t");
120	}
121	
122	pub fn stringify(
123	    globalThis: *jsc.JSGlobalObject,
124	    callframe: *jsc.CallFrame,
125	) bun.JSError!jsc.JSValue {
126	    const arguments = callframe.arguments_old(1).slice();
127	    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
128	        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
129	    }
130	
131	    const value = arguments[0];
132	    if (!value.isObject()) {
133	        return globalThis.throwInvalidArguments("Expected an object to stringify", .{});
134	    }
135	
136	    var builder: wtf.StringBuilder = .init();
137	    defer builder.deinit();
138	
139	    // First pass: emit root-level primitive key=value pairs
140	    {
141	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
142	            globalThis,
143	            try value.toObject(globalThis),
144	        );
145	        defer iter.deinit();
146	
147	        while (try iter.next()) |prop_name| {
148	            const prop_val = iter.value;
149	            // Skip objects (sections) in first pass, skip undefined/functions/symbols
150	            if (prop_val.isObject() or prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) continue;
151	
152	            appendKeyName(&builder, prop_name);
153	            builder.append(.latin1, " = ");
154	            try appendValue(&builder, globalThis, prop_val);
155	            builder.append(.lchar, '\n');
156	        }
157	    }
158	
159	    // Second pass: emit sections (object values)
160	    {
161	        var first_section = true;
