208	fn appendValue(builder: *wtf.StringBuilder, globalThis: *jsc.JSGlobalObject, val: jsc.JSValue) bun.JSError!void {
209	    if (val.isNull()) {
210	        builder.append(.latin1, "null");
211	        return;
212	    }
213	
214	    if (val.isBoolean()) {
215	        builder.append(.latin1, if (val.asBoolean()) "true" else "false");
