228	    if (val.isString()) {
229	        const str = try val.toBunString(globalThis);
230	        defer str.deref();
231	        builder.append(.string, str);
232	        return;
233	    }
234	
235	    // For anything else (arrays, nested objects inside sections, etc.), use toString
236	    const str = try val.toBunString(globalThis);
237	    defer str.deref();
238	    builder.append(.string, str);
239	}
